import { marked } from "marked";
import { parseChrome } from "../../chrome";
import type { Chrome } from "../../chrome";

let tableIdCounter = 0;

const toCssValue = (raw: string): string => /^\d+(\.\d+)?$/.test(raw) ? `${raw}px` : raw;

type CellAlign = "left" | "right" | "center" | undefined;

type DataRow = Readonly<{ type: "header" | "data"; cells: readonly string[] }>;
type DetailRow = Readonly<{ type: "detail"; content: string }>;
type ParsedRow = DataRow | DetailRow;

type GridCell =
  | Readonly<{ skip: true }>
  | Readonly<{ text: string; rs: number; cs: number; width?: string; type: "header" | "data" }>;

type GridRow =
  | Readonly<{ type: "detail"; content: string }>
  | Readonly<{ type: "header" | "data"; gridRow: readonly GridCell[] }>;

export const resetTableCounter = (): void => {
  tableIdCounter = 0;
};

const parseSeparatorAlignments = (line: string): readonly CellAlign[] =>
  line.split("|").slice(1, -1).map((seg) => {
    const t = seg.trim();
    const left = t.startsWith(":");
    const right = t.endsWith(":");
    if (left && right) return "center";
    if (right) return "right";
    if (left) return "left";
    return undefined;
  });

const parseRows = (block: string): Readonly<{ rows: readonly ParsedRow[]; alignments: readonly CellAlign[] }> => {
  const lines = block.trim().split("\n");
  const rows: ParsedRow[] = [];
  let isHeader = true;
  let alignments: readonly CellAlign[] = [];

  for (const line of lines) {
    const trimmed = line.trim();
    if (/^\|[\s-:|]+\|$/.test(trimmed)) {
      alignments = parseSeparatorAlignments(trimmed);
      isHeader = false;
      continue;
    }

    if (trimmed.startsWith("|>")) {
      rows.push({ type: "detail", content: trimmed.slice(2).replaceAll(/\|$/g, "").trim() });
      continue;
    }

    if (!trimmed.startsWith("|")) {
      continue;
    }

    const cells = trimmed
      .split("|")
      .slice(1, -1)
      .map((cell) => cell.trim());

    rows.push({ type: isHeader ? "header" : "data", cells });
  }

  return { rows, alignments };
};

const processDataRowCells = (row: DataRow, rsTrack: Map<number, number>): GridCell[] => {
  const gridRow: GridCell[] = [];
  let cellIndex = 0;
  let columnIndex = 0;

  while (cellIndex < row.cells.length || (rsTrack.get(columnIndex) ?? 0) > 0) {
    const tracked = rsTrack.get(columnIndex) ?? 0;
    if (tracked > 0) {
      const raw = row.cells[cellIndex] ?? "";
      if (raw === "^^" || raw === "") {
        rsTrack.set(columnIndex, tracked - 1);
        gridRow.push({ skip: true });
        columnIndex += 1;
        cellIndex += 1;
        continue;
      }
      rsTrack.set(columnIndex, 0);
    }

    if (cellIndex >= row.cells.length) {
      break;
    }

    let text = row.cells[cellIndex] ?? "";
    let cs = 1;
    let rs = 1;
    let width: string | undefined;

    text = text.replaceAll(/\[cs=(\d+)\]/g, (_m, n: string) => {
      cs = Number.parseInt(n, 10);
      return "";
    });
    text = text.replaceAll(/\[rs=(\d+)\]/g, (_m, n: string) => {
      rs = Number.parseInt(n, 10);
      return "";
    });
    text = text.replaceAll(/\[w=(\S+?)\]/g, (_m, v: string) => {
      width = toCssValue(v);
      return "";
    });

    const normalized = text.trim();
    if (rs > 1) {
      rsTrack.set(columnIndex, rs - 1);
    }

    const cellEntry: GridCell = width
      ? { text: normalized, rs, cs, width, type: row.type }
      : { text: normalized, rs, cs, type: row.type };
    gridRow.push(cellEntry);
    columnIndex += 1;

    for (let span = 1; span < cs; span += 1) {
      gridRow.push({ skip: true });
      columnIndex += 1;
      cellIndex += 1;
    }

    cellIndex += 1;
  }

  return gridRow;
};

const toGridRows = (rows: readonly ParsedRow[]): readonly GridRow[] => {
  const rsTrack = new Map<number, number>();
  const grid: GridRow[] = [];

  for (const row of rows) {
    if (row.type === "detail") {
      grid.push(row);
    } else {
      grid.push({ type: row.type, gridRow: processDataRowCells(row, rsTrack) });
    }
  }

  return grid;
};

const adjustedRowspan = (grid: readonly GridRow[], startIndex: number, originalRs: number): number => {
  let dataCount = 0;
  let endIndex = startIndex;

  while (endIndex < grid.length && dataCount < originalRs) {
    if (grid[endIndex]?.type !== "detail") {
      dataCount += 1;
    }

    if (dataCount < originalRs) {
      endIndex += 1;
    }
  }

  return endIndex - startIndex + 1;
};

const renderDetailRowHtml = (tableId: string, detailIndex: number, content: string): string => {
  const detailId = `${tableId}-d${detailIndex}`;
  return (
    `<tr class="detail-row" id="${detailId}">` +
    `<td colspan="100" style="padding:0;border-bottom:1px solid var(--border);overflow:hidden;">` +
    `<div class="detail-inner" style="max-height:0;overflow:hidden;padding:0 20px;background:var(--blockquote-bg);border-left:3px solid var(--accent);transition:max-height 0.35s cubic-bezier(0.4,0,0.2,1),padding 0.35s cubic-bezier(0.4,0,0.2,1);">` +
    `<div class="detail-web" style="font-size:0.93em;line-height:1.7;overflow-wrap:break-word;word-break:break-word;">${content}</div>` +
    `</div></td></tr>`
  );
};



const inlineMarkdown = (text: string): string => {
  const result = marked.parseInline(text);
  return typeof result === "string" ? result : text;
};

type CellHtmlOptions = Readonly<{
  text: string;
  cs: number;
  rs: number;
  isHeader: boolean;
  grid: readonly GridRow[];
  rowIndex: number;
  align?: CellAlign;
  width?: string;
}>;

const buildCellHtml = (opts: CellHtmlOptions): string => {
  const { text, cs, rs, isHeader, grid, rowIndex, align, width } = opts;
  const tag = isHeader ? "th" : "td";
  const csAttr = cs > 1 ? ` colspan="${cs}"` : "";
  const effectiveRs = rs > 1 ? adjustedRowspan(grid, rowIndex, rs) : rs;
  const rsAttr = effectiveRs > 1 ? ` rowspan="${effectiveRs}"` : "";
  const textAlign = align ? `text-align:${align};` : "";
  const widthStyle = width ? `width:${width};min-width:${width};` : "min-width:120px;";

  let style = `padding:10px 16px;border-bottom:1px solid var(--border);${widthStyle}${textAlign}`;
  if (isHeader) {
    style += "font-weight:600;font-size:0.85em;text-transform:uppercase;letter-spacing:0.04em;color:var(--text-muted);background:var(--code-bg);white-space:nowrap;";
  }

  return `<${tag}${csAttr}${rsAttr} style="${style}">${inlineMarkdown(text)}</${tag}>`;
};

const EXPAND_CHEVRON = '<span class="expand-chevron" style="display:inline-flex;align-items:center;justify-content:center;width:18px;height:18px;margin-right:8px;transition:transform 0.25s cubic-bezier(0.4,0,0.2,1);vertical-align:middle;color:var(--accent);flex-shrink:0;"><svg width="10" height="10" viewBox="0 0 10 10" fill="none"><path d="M3 1l4 4-4 4" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/></svg></span>';

const buildCellOpts = (
  text: string,
  cell: Exclude<GridCell, { skip: true }>,
  isHeader: boolean,
  grid: readonly GridRow[],
  rowIndex: number,
  align: CellAlign,
): CellHtmlOptions => {
  const base: CellHtmlOptions = { text, cs: cell.cs, rs: cell.rs, isHeader, grid, rowIndex };
  const cellWidth = cell.width;
  if (align && cellWidth) return { ...base, align, width: cellWidth };
  if (align) return { ...base, align };
  if (cellWidth) return { ...base, width: cellWidth };
  return base;
};

const renderDataRowHtml = (
  row: Exclude<GridRow, { type: "detail" }>,
  grid: readonly GridRow[],
  rowIndex: number,
  tableId: string,
  detailIndex: number,
  alignments: readonly CellAlign[],
): string => {
  const first = row.gridRow[0];
  const isHeader = first !== undefined && "type" in first && first.type === "header";
  const detailTarget = grid[rowIndex + 1]?.type === "detail" ? `${tableId}-d${detailIndex}` : "";

  const rowAttrs = detailTarget
    ? ` class="expandable-row" data-detail="${detailTarget}" style="cursor:pointer;"`
    : "";
  let html = `<tr${rowAttrs}>`;

  let isFirstData = true;
  let cellIdx = 0;
  for (const cell of row.gridRow) {
    if ("skip" in cell) {
      continue;
    }

    let content = cell.text;
    if (!isHeader && detailTarget && isFirstData) {
      content = `${EXPAND_CHEVRON}${content}`;
      isFirstData = false;
    } else if (!isHeader) {
      isFirstData = false;
    }

    html += buildCellHtml(buildCellOpts(content, cell, isHeader, grid, rowIndex, alignments[cellIdx]));
    cellIdx += 1;
  }

  html += "</tr>";
  return html;
};

const renderGrid = (grid: readonly GridRow[], alignments: readonly CellAlign[], chrome: Chrome = {}): string => {
  const tableId = `ctbl-${tableIdCounter++}`;
  const isResponsive = Boolean(chrome.responsive);
  const title = chrome.title && chrome.title !== "true" ? chrome.title : "";
  const wrapWidth = chrome.width ? `width:${toCssValue(chrome.width)};` : "";
  const wrapHeight = chrome.height ? `height:${toCssValue(chrome.height)};` : "";
  const titleBar = title
    ? `<div style="font-family:'JetBrains Mono',monospace;font-size:0.7em;text-transform:uppercase;letter-spacing:0.08em;color:var(--accent);font-weight:600;padding:8px 14px;border-bottom:1px solid var(--border);">${title}</div>`
    : "";
  let html = `<div class="complex-table-wrap" style="overflow-x:auto;margin:16px 0;border-radius:10px;border:1px solid var(--border);${wrapWidth}${wrapHeight}">${titleBar}`;
  const tableWidth = isResponsive ? "" : "width:100%;";
  html += `<table id="${tableId}" class="complex-table" style="${tableWidth}border-collapse:collapse;font-size:0.92em;">`;

  let detailIndex = 0;

  for (let rowIndex = 0; rowIndex < grid.length; rowIndex += 1) {
    const row = grid[rowIndex];
    if (!row) {
      continue;
    }

    if (row.type === "detail") {
      html += renderDetailRowHtml(tableId, detailIndex, row.content);
      detailIndex += 1;
      continue;
    }

    html += renderDataRowHtml(row, grid, rowIndex, tableId, detailIndex, alignments);
  }

  html += "</table></div>";
  return html;
};

const parseComplexTable = (block: string, chrome: Chrome): string => {
  const { rows, alignments } = parseRows(block);
  const grid = toGridRows(rows);
  return renderGrid(grid, alignments, chrome);
};

export const preProcessComplexTables = (md: string): string => {
  return md.replaceAll(/^:::table(?:\s+\{([^}]*)\})?\s*\n([\s\S]*?)^:::\s*$/gm, (_m, flags: string | undefined, content: string) => {
    const chrome = flags ? parseChrome(flags) : {};
    return `\n${parseComplexTable(content, chrome)}\n`;
  });
};
