export const vizLibsReady: Promise<void> = Promise.all([
  import("echarts").then((m) => { globalThis.echarts = m as typeof globalThis.echarts; }),
  import("d3").then((m) => { globalThis.d3 = m; }),
  import("three").then((m) => { globalThis.THREE = m; }),
  import("mermaid").then((m) => { globalThis.mermaid = m.default as unknown as typeof globalThis.mermaid; }),
]) as unknown as Promise<void>;
