import { parseChrome } from "../../chrome";

export const preProcessColumns = (md: string): string => {
  return md.replaceAll(/^:::columns-(\d+)(?:\s+\{([^}]*)\})?\s*\n([\s\S]*?)^:::\s*$/gm, (_m, _n: string, flags: string | undefined, content: string) => {
    const chrome = flags ? parseChrome(flags) : {};
    const title = chrome.title && chrome.title !== "true" ? chrome.title : "";
    const cols = content.split(/^\+\+\+\s*$/m);
    const divs = cols
      .map((column) => `<div class="md-col" style="flex:1;min-width:180px;">\n\n${column.trim()}\n\n</div>`)
      .join("\n");

    const titleBar = title
      ? `<div style="font-family:'JetBrains Mono',monospace;font-size:0.7em;text-transform:uppercase;letter-spacing:0.08em;color:var(--accent);font-weight:600;margin-bottom:12px;">${title}</div>\n`
      : "";
    return `<div class="md-columns" style="display:flex;flex-wrap:wrap;gap:24px;">\n${titleBar}${divs}\n</div>\n`;
  });
};
