const ICON_RE = /:(?:(fas|far|fab|di|dic)-)([\w-]+?)(?:\.([\w.]+?))?:/g;

const SIZE_MAP: Readonly<Record<string, string>> = {
  lg: "fa-lg",
  "2x": "fa-2x",
  "3x": "fa-3x",
  "4x": "fa-4x",
  "5x": "fa-5x",
};

const ANIM_MAP: Readonly<Record<string, string>> = {
  spin: "fa-spin",
  beat: "fa-beat",
  bounce: "fa-bounce",
};

export const preProcessIcons = (md: string): string => {
  return md.replaceAll(ICON_RE, (_m, prefix: string, name: string, mods?: string) => {
    let classes = "";

    if (prefix === "fas") classes = `fa-solid fa-${name}`;
    else if (prefix === "far") classes = `fa-regular fa-${name}`;
    else if (prefix === "fab") classes = `fa-brands fa-${name}`;
    else if (prefix === "di") classes = `devicon-${name}-plain`;
    else if (prefix === "dic") classes = `devicon-${name}-plain colored`;

    let extras = "";
    if (mods) {
      for (const mod of mods.split(".")) {
        if (SIZE_MAP[mod]) extras += ` ${SIZE_MAP[mod]}`;
        else if (ANIM_MAP[mod]) extras += ` ${ANIM_MAP[mod]}`;
      }
    }

    return `<i class="${classes}${extras}"></i>`;
  });
};
