export type Chrome = Readonly<Record<string, string>>;

const parseQuoted = (raw: string, start: number): Readonly<{ value: string; end: number }> => {
  let value = "";
  let i = start;
  while (i < raw.length && raw[i] !== '"') {
    if (raw[i] === "\\" && i + 1 < raw.length) {
      i += 1;
      value += raw.charAt(i);
    } else {
      value += raw.charAt(i);
    }
    i += 1;
  }
  return { value, end: i < raw.length ? i + 1 : i };
};

const nextToken = (raw: string, start: number): Readonly<{ token: string; end: number }> => {
  let token = "";
  let i = start;
  while (i < raw.length && raw[i] !== " " && raw[i] !== "\t") {
    if (raw[i] === '"') {
      const quoted = parseQuoted(raw, i + 1);
      token += quoted.value;
      i = quoted.end;
    } else {
      token += raw.charAt(i);
      i += 1;
    }
  }
  return { token, end: i };
};

const tokenize = (raw: string): readonly string[] => {
  const tokens: string[] = [];
  let i = 0;
  while (i < raw.length) {
    if (raw[i] === " " || raw[i] === "\t") { i += 1; continue; }
    const result = nextToken(raw, i);
    if (result.token) tokens.push(result.token);
    i = result.end;
  }
  return tokens;
};

export const parseChrome = (raw: string): Chrome => {
  const chrome: Record<string, string> = {};
  for (const token of tokenize(raw)) {
    const sep = token.indexOf(":");
    if (sep > 0) {
      chrome[token.slice(0, sep)] = token.slice(sep + 1);
    } else {
      chrome[token] = "true";
    }
  }
  return chrome;
};
