import { CHROME_FLAGS } from "../constants";
import { parseChrome } from "../chrome";
import type { VizChrome } from "../types";

export const parseVizLang = (rawLang: string | undefined): Readonly<{ lang: string | undefined; chrome: VizChrome }> => {
  if (!rawLang) {
    return { lang: rawLang, chrome: {} };
  }

  const match = /^(\S+?)(?:\s*\{([^}]*)\})?$/.exec(rawLang);
  if (!match) {
    return { lang: rawLang, chrome: {} };
  }

  const base = match[2] ? parseChrome(match[2]) : {};
  const chrome: Record<string, string> = {};
  for (const [key, value] of Object.entries(base)) {
    const isKv = value !== "true";
    if (isKv || CHROME_FLAGS.has(key)) {
      chrome[key] = isKv ? value : "1";
    }
  }

  return {
    lang: match[1],
    chrome,
  };
};
