import { VIZ_LABELS, VIZ_LANGS } from "../constants";
import { hashStr } from "../viz/hash";
import { parseVizLang } from "./vizLangParser";
import { highlightCode } from "./prismHighlight";

const toCssValue = (raw: string): string => /^\d+(\.\d+)?$/.test(raw) ? `${raw}px` : raw;

const escapeCode = (text: string): string => {
  return text
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;");
};

const encodeCode = (text: string): string => {
  const bytes = new TextEncoder().encode(text);
  const binary = Array.from(bytes, (byte) => String.fromCodePoint(byte)).join("");
  return btoa(binary);
};

const buildVizBar = (chrome: Readonly<Record<string, string>>, lang: string, hasBorder: boolean): string => {
  const hasTitle = Boolean(chrome.title);
  const hasBadge = Boolean(chrome.badge);
  if (!hasTitle && !hasBadge) return "";

  const borderStyle = hasBorder ? "border-bottom:1px solid var(--border);" : "";
  const titleText = hasTitle && chrome.title !== "1" ? chrome.title : (VIZ_LABELS[lang] ?? lang);
  const titleEl = hasTitle
    ? `<span style="font-family:'JetBrains Mono',monospace;font-size:0.7em;text-transform:uppercase;letter-spacing:0.08em;color:var(--accent);font-weight:600;">${titleText}</span>`
    : "<span></span>";
  const badgeEl = hasBadge
    ? '<span style="font-size:0.65em;color:var(--text-muted);">live</span>'
    : "";

  return `<div style="display:flex;align-items:center;justify-content:space-between;padding:6px 14px;${borderStyle}">${titleEl}${badgeEl}</div>`;
};

const toHeadingId = (value: string): string => {
  return value
    .replaceAll(/<[^>]*>/g, "")
    .replaceAll(/&[a-z0-9#]+;/gi, " ")
    .toLowerCase()
    .replaceAll(/[^\w]+/g, "-")
    .replaceAll(/-+/g, "-")
    .replaceAll(/(^-|-$)/g, "");
};

const renderVizBlock = (text: string, lang: string, chrome: Record<string, string>): string => {
  const codeHash = hashStr(`${lang}:${text}`);
  const encoded = encodeCode(text);
  const hasBorder = Boolean(chrome.border);
  const hasBg = Boolean(chrome.bg);
  const wrapStyle = `margin:16px 0;${hasBorder ? "border-radius:10px;border:1px solid var(--border);" : ""}${hasBg ? "background:var(--code-bg);" : ""}`;
  const bar = buildVizBar(chrome, lang, hasBorder);
  const defaultMinHeight = lang === "mermaid" ? "80" : "300";
  const minHeight = toCssValue(lang === "mermaid" ? defaultMinHeight : (chrome.height ?? defaultMinHeight));
  const sizeAttrs = ["height", "width", "padding", "align"].map((key) => chrome[key] ? ` data-viz-${key}="${chrome[key]}"` : "").join("");
  const padding = chrome.padding ? `padding:${toCssValue(chrome.padding)};` : "";
  const mermaidClass = lang === "mermaid" ? " viz-mermaid" : "";

  return `<div class="web-viz${mermaidClass}" data-viz-lang="${lang}" data-viz-hash="${codeHash}" data-viz-code="${encoded}"${sizeAttrs} style="${wrapStyle}">${bar}<div id="viz-${codeHash}" class="viz-content" style="width:100%;min-height:${minHeight};${padding}display:flex;align-items:center;justify-content:center;color:var(--text-muted);font-size:0.85em;">Loading…</div></div>`;
};

const renderCodeBlock = (text: string, lang: string | undefined, rawLang: string | undefined): string => {
  const escaped = escapeCode(text);
  const highlighted = lang ? highlightCode(text, lang) : "";
  const codeHtml = highlighted || escaped;
  const displayLang = lang || rawLang || "";
  const label = displayLang
    ? `<div style="position:absolute;top:0;right:0;padding:4px 12px;font-size:0.7em;text-transform:uppercase;letter-spacing:0.08em;color:var(--text-muted);background:var(--code-bg);border-radius:0 8px 0 8px;font-family:'JetBrains Mono','Fira Code',monospace;">${displayLang}</div>`
    : "";
  const encodedSource = encodeCode(text);
  const copyBtn = `<button type="button" class="code-copy-btn" data-code="${encodedSource}" aria-label="Copy code" title="Copy code"><svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><rect x="9" y="9" width="13" height="13" rx="2"/><path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1"/></svg></button>`;

  return `<div class="code-block-wrapper" style="position:relative;margin:16px 0;">${label}${copyBtn}<pre style="background:var(--code-bg);padding:20px;border-radius:8px;overflow-x:auto;margin:0;border:1px solid var(--border);"><code class="language-${displayLang || "text"}" style="font-family:'JetBrains Mono','Fira Code',monospace;font-size:0.85em;line-height:1.7;">${codeHtml}</code></pre></div>`;
};

export const configureMarked = (markedLib: { setOptions: (options: unknown) => unknown; use: (options: unknown) => unknown }): void => {
  markedLib.setOptions({ gfm: true, breaks: false });

  const renderer = {
    heading(this: { parser: { parseInline: (tokens: unknown) => string } }, { tokens, depth }: { tokens: unknown; depth: number }) {
      const text = this.parser.parseInline(tokens);
      const sizes: Record<number, string> = { 1: "2.2em", 2: "1.65em", 3: "1.3em", 4: "1.12em", 5: "1em", 6: "0.88em" };
      const weights: Record<number, string> = { 1: "800", 2: "700", 3: "700", 4: "600", 5: "600", 6: "600" };
      const margins: Record<number, string> = { 1: "44px 0 18px", 2: "36px 0 14px", 3: "28px 0 12px", 4: "22px 0 10px", 5: "18px 0 8px", 6: "14px 0 6px" };
      const id = toHeadingId(text);
      return `<h${depth} id="${id}" style="font-size:${sizes[depth]};font-weight:${weights[depth]};margin:${margins[depth]};line-height:1.3;letter-spacing:-0.02em;">${text}</h${depth}>`;
    },
    paragraph(this: { parser: { parseInline: (tokens: unknown) => string } }, { tokens }: { tokens: unknown }) {
      return `<p style="margin:12px 0;line-height:1.78;">${this.parser.parseInline(tokens)}</p>\n`;
    },
    blockquote(this: { parser: { parse: (tokens: unknown) => string } }, { tokens }: { tokens: unknown }) {
      return `<blockquote style="border-left:3px solid var(--blockquote-border);background:var(--blockquote-bg);margin:16px 0;padding:16px 20px;border-radius:0 8px 8px 0;">${this.parser.parse(tokens)}</blockquote>`;
    },
    code({ text, lang: rawLang }: { text: string; lang?: string }) {
      const { lang, chrome } = parseVizLang(rawLang);
      if (lang && VIZ_LANGS.has(lang)) {
        return renderVizBlock(text, lang, chrome);
      }

      return renderCodeBlock(text, lang, rawLang);
    },
    codespan({ text }: { text: string }) {
      return `<code style="background:var(--code-bg);color:var(--code-text);padding:2px 6px;border-radius:4px;font-size:0.88em;font-family:'JetBrains Mono','Fira Code',monospace;">${text}</code>`;
    },
    table(this: { parser: { parseInline: (tokens: unknown) => string } }, { header, rows }: { header: Array<{ align?: string; tokens: unknown }>; rows: Array<Array<{ align?: string; tokens: unknown }>> }) {
      const hdr = header.map((cell) => {
        const align = `text-align:${cell.align ?? "left"};`;
        return `<th style="padding:10px 16px;min-width:120px;white-space:nowrap;${align}font-weight:600;font-size:0.85em;text-transform:uppercase;letter-spacing:0.04em;color:var(--text-muted);border-bottom:2px solid var(--border);">${this.parser.parseInline(cell.tokens)}</th>`;
      }).join("");

      const body = rows.map((row, rowIndex) => {
        const bg = rowIndex % 2 === 1 ? "var(--table-stripe)" : "transparent";
        const cells = row.map((cell) => {
          const align = `text-align:${cell.align ?? "left"};`;
          return `<td style="padding:10px 16px;min-width:120px;${align}border-bottom:1px solid var(--border);">${this.parser.parseInline(cell.tokens)}</td>`;
        }).join("");
        return `<tr style="background:${bg};">${cells}</tr>`;
      }).join("");

      return `<div style="overflow-x:auto;margin:16px 0;border-radius:8px;border:1px solid var(--border);"><table style="width:100%;border-collapse:collapse;font-size:0.92em;table-layout:fixed;"><thead><tr>${hdr}</tr></thead><tbody>${body}</tbody></table></div>`;
    },
    list(this: { listitem: (item: unknown) => string }, { ordered, items }: { ordered: boolean; items: unknown[] }) {
      const tag = ordered ? "ol" : "ul";
      return `<${tag} style="padding-left:24px;margin:12px 0;line-height:1.8;">${items.map((item) => this.listitem(item)).join("")}</${tag}>`;
    },
    listitem(this: { parser: { parse: (tokens: unknown, loose: boolean) => string } }, item: { tokens: unknown; loose?: boolean; task?: boolean; checked?: boolean }) {
      let body = this.parser.parse(item.tokens, Boolean(item.loose));
      if (item.task) {
        const checked = Boolean(item.checked);
        const box = `<span style="width:18px;height:18px;border-radius:4px;border:2px solid ${checked ? "var(--accent)" : "var(--border)"};background:${checked ? "var(--accent)" : "transparent"};display:inline-flex;align-items:center;justify-content:center;flex-shrink:0;margin-right:8px;vertical-align:middle;">${checked ? '<svg width="12" height="12" viewBox="0 0 12 12" fill="none"><path d="M2.5 6L5 8.5L9.5 3.5" stroke="white" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"/></svg>' : ""}</span>`;
        body = body.replaceAll(/<input.*?>/g, "");
        return `<li style="list-style:none;margin-left:-20px;">${box}${body}</li>`;
      }
      return `<li>${body}</li>`;
    },
    hr() {
      return `<hr style="border:none;height:1px;background:var(--border);margin:28px 0;" />`;
    },
    image({ href, title, text }: { href: string; title?: string; text: string }) {
      const titleAttr = title ? ` title="${title}"` : "";
      const caption = text ? `<figcaption style="margin-top:8px;font-size:0.85em;color:var(--text-muted);font-style:italic;">${text}</figcaption>` : "";
      return `<figure style="margin:20px 0;text-align:center;"><img src="${href}" alt="${text}"${titleAttr} style="max-width:100%;border-radius:10px;box-shadow:var(--shadow);" />${caption}</figure>`;
    },
    link(this: { parser: { parseInline: (tokens: unknown) => string } }, { href, title, tokens }: { href: string; title?: string; tokens: unknown }) {
      const titleAttr = title ? ` title="${title}"` : "";
      const isExternal = /^(?:[a-z][a-z0-9+.-]*:|\/\/)/i.test(href);
      const attrs = isExternal ? ' target="_blank" rel="noopener"' : "";
      return `<a href="${href}"${titleAttr}${attrs} style="color:var(--accent);text-decoration:underline;text-underline-offset:3px;">${this.parser.parseInline(tokens)}</a>`;
    },
    del(this: { parser: { parseInline: (tokens: unknown) => string } }, { tokens }: { tokens: unknown }) {
      return `<del style="opacity:0.6">${this.parser.parseInline(tokens)}</del>`;
    },
  };

  markedLib.use({ renderer });
};
