const LANG_ALIASES: Readonly<Record<string, string>> = {
  html: "markup",
  xml: "markup",
  svg: "markup",
  js: "javascript",
  ts: "typescript",
  py: "python",
  rb: "ruby",
  rs: "rust",
  cs: "csharp",
  sh: "bash",
  shell: "bash",
  zsh: "bash",
  yml: "yaml",
  dockerfile: "docker",
  make: "makefile",
  tex: "latex",
  gql: "graphql",
  kt: "kotlin",
  hs: "haskell",
  ps1: "powershell",
  "c++": "cpp",
  "c#": "csharp",
};

export const highlightCode = (code: string, lang: string): string => {
  const resolved = LANG_ALIASES[lang] ?? lang;
  const grammar = Prism.languages[resolved];
  if (!grammar) return "";
  try {
    return Prism.highlight(code, grammar, resolved);
  } catch {
    return "";
  }
};
